module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

    reg [size-1:0] mul_a_ext, mul_b_ext;
    reg [2*size-1:0] partial_products [size-1:0];
    reg [2*size-1:0] sum_reg1, sum_reg2;

    integer i;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_a_ext <= 0;
            mul_b_ext <= 0;
            for (i = 0; i < size; i = i + 1) begin
                partial_products[i] <= 0;
            end
            sum_reg1 <= 0;
            sum_reg2 <= 0;
            mul_out <= 0;
        end else begin
            mul_a_ext <= mul_a;
            mul_b_ext <= mul_b;
            for (i = 0; i < size; i = i + 1) begin
                partial_products[i] <= (mul_b_ext[i]) ? (mul_a_ext << i) : 'd0;
            end
            sum_reg1 <= partial_products[0] + partial_products[1];
            sum_reg2 <= partial_products[2] + partial_products[3];
            mul_out <= sum_reg1 + sum_reg2;
        end
    end

endmodule
